446→/** Log an implementation note on an entity */
447→export async function logImplementationNote(input: {
448→  surreal: Surreal;
449→  entityTable: string;
450→  entityId: string;
451→  note: string;
452→  filesChanged?: string[];
453→}): Promise<{ entity_id: string; note_added: boolean }> {
454→  const record = new RecordId(input.entityTable, input.entityId);
455→  const entity = await input.surreal.select<{ description_entries?: Array<{ text: string; source?: RecordId; created_at: Date }> }>(record);
456→
457→  if (!entity) throw new Error(`entity not found: ${input.entityTable}:${input.entityId}`);
458→
459→  const now = new Date();
460→  const entries = entity.description_entries ?? [];
461→  const noteText = input.filesChanged?.length
462→    ? `${input.note}\n\nFiles: ${input.filesChanged.join(", ")}`
463→    : input.note;
464→
465→  entries.push({ text: noteText, created_at: now });
466→
467→  await input.surreal.update(record).merge({
468→    description_entries: entries,
469→    updated_at: now,
470→  });
471→
472→  return { entity_id: `${input.entityTable}:${input.entityId}`, note_added: true };
473→}
