475→/** Create or finalize an agent session */
476→export async function createAgentSession(input: {
477→  surreal: Surreal;
478→  agent: string;
479→  directory: string;
480→  workspaceRecord: RecordId<"workspace", string>;
481→  projectRecord: RecordId<"project", string>;
482→  taskId?: string;
483→}): Promise<{ session_id: string }> {
484→  const now = new Date();
485→  const sessionRecord = new RecordId("agent_session", randomUUID());
486→
487→  await input.surreal.create(sessionRecord).content({
488→    agent: input.agent,
489→    directory: input.directory,
490→    started_at: now,
491→    workspace: input.workspaceRecord,
492→    project: input.projectRecord,
493→    created_at: now,
494→    ...(input.taskId ? { task_id: new RecordId("task", input.taskId) } : {}),
495→  });
496→
497→  // If task-scoped, auto-update task status to in_progress
498→  if (input.taskId) {
499→    const taskRecord = new RecordId("task", input.taskId);
500→    const task = await input.surreal.select<TaskRow>(taskRecord);
501→    if (task && (task.status === "todo" || task.status === "ready")) {
502→      await input.surreal.update(taskRecord).merge({
503→        status: "in_progress",
504→        updated_at: now,
505→      });
506→    }
507→  }
508→
509→  return { session_id: toId(sessionRecord) };
510→}
511→
512→/** End an agent session with summary */
513→export async function endAgentSession(input: {
514→  surreal: Surreal;
515→  sessionId: string;
516→  summary: string;
517→  decisionsMade?: string[];
518→  questionsAsked?: string[];
519→  tasksProgressed?: Array<{ task_id: string; from_status: string; to_status: string }>;
520→  filesChanged?: Array<{ path: string; change_type: string }>;
521→}): Promise<{ session_id: string; ended: boolean }> {
522→  const now = new Date();
523→  const sessionRecord = new RecordId("agent_session", input.sessionId);
524→
525→  await input.surreal.update(sessionRecord).merge({
526→    ended_at: now,
527→    summary: input.summary,
528→    ...(input.decisionsMade?.length
529→      ? { decisions_made: input.decisionsMade.map((id) => new RecordId("decision", id)) }
530→      : {}),
531→    ...(input.questionsAsked?.length
532→      ? { questions_asked: input.questionsAsked.map((id) => new RecordId("question", id)) }
533→      : {}),
534→    ...(input.tasksProgressed?.length
535→      ? {
536→          tasks_progressed: input.tasksProgressed.map((t) => ({
537→            task_id: new RecordId("task", t.task_id),
538→            from_status: t.from_status,
539→            to_status: t.to_status,
540→          })),
541→        }
542→      : {}),
543→    ...(input.filesChanged?.length ? { files_changed: input.filesChanged } : {}),
544→  });
545→
546→  // Create session -> entity edges
547→  if (input.decisionsMade?.length) {
548→    for (const decisionId of input.decisionsMade) {
549→      await input.surreal
550→        .relate(sessionRecord, new RecordId("produced", randomUUID()), new RecordId("decision", decisionId), {
551→          added_at: now,
552→        })
553→        .output("after");
554→    }
555→  }
556→
557→  if (input.questionsAsked?.length) {
558→    for (const questionId of input.questionsAsked) {
559→      await input.surreal
560→        .relate(sessionRecord, new RecordId("asked", randomUUID()), new RecordId("question", questionId), {
561→          added_at: now,
562→        })
563→        .output("after");
564→    }
565→  }
566→
567→  if (input.tasksProgressed?.length) {
568→    for (const t of input.tasksProgressed) {
569→      await input.surreal
570→        .relate(sessionRecord, new RecordId("progressed", randomUUID()), new RecordId("task", t.task_id), {
571→          from_status: t.from_status,
572→          to_status: t.to_status,
573→          added_at: now,
574→        })
575→        .output("after");
576→    }
577→  }
578→
579→  return { session_id: toId(sessionRecord), ended: true };
580→}
581→
582→/** Log a git commit to the graph */
583→export async function logCommit(input: {
584→  surreal: Surreal;
585→  workspaceRecord: RecordId<"workspace", string>;
586→  projectRecord: RecordId<"project", string>;
587→  sha: string;
588→  message: string;
589→  filesChanged: Array<{ path: string; change_type: string; lines_added: number; lines_removed: number }>;
590→  author: string;
591→  taskUpdates?: Array<{ task_id: string; new_status: string }>;
592→  decisionsDetected?: Array<{ name: string; rationale: string }>;
593→}): Promise<{ commit_id: string; tasks_updated: number; decisions_created: number }> {
594→  const now = new Date();
595→  const commitRecord = new RecordId("git_commit", randomUUID());
596→
597→  await input.surreal.create(commitRecord).content({
598→    sha: input.sha,
599→    message: input.message,
600→    workspace: input.workspaceRecord,
601→    authored_at: now,
602→    created_at: now,
603→  });
604→
605→  // Update task statuses
606→  let tasksUpdated = 0;
607→  if (input.taskUpdates?.length) {
608→    for (const update of input.taskUpdates) {
609→      const taskRecord = new RecordId("task", update.task_id);
610→      await input.surreal.update(taskRecord).merge({
611→        status: update.new_status,
612→        updated_at: now,
613→      });
614→      tasksUpdated++;
615→    }
616→  }
617→
618→  // Create provisional decisions if flagged
619→  let decisionsCreated = 0;
620→  if (input.decisionsDetected?.length) {
621→    for (const decision of input.decisionsDetected) {
622→      const decisionRecord = new RecordId("decision", randomUUID());
623→      await input.surreal.create(decisionRecord).content({
624→        summary: decision.name,
625→        rationale: decision.rationale,
626→        status: "provisional",
627→        decided_by_name: "code-agent",
628→        workspace: input.workspaceRecord,
629→        source_commit: commitRecord,
630→        created_at: now,
631→        updated_at: now,
632→      });
633→
634→      // Link decision to project
635→      await input.surreal
636→        .relate(decisionRecord, new RecordId("belongs_to", randomUUID()), input.projectRecord, {
637→          added_at: now,
638→        })
639→        .output("after");
640→
641→      // Create implemented_by edge
642→      await input.surreal
643→        .relate(decisionRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
644→          commit_sha: input.sha,
645→          linked_at: now,
646→        })
647→        .output("after");
648→
649→      decisionsCreated++;
650→    }
651→  }
652→
653→  return {
654→    commit_id: toId(commitRecord),
655→    tasks_updated: tasksUpdated,
656→    decisions_created: decisionsCreated,
657→  };
658→}
659→
660→// ---------------------------------------------------------------------------
661→// Utility
662→// ---------------------------------------------------------------------------
663→
664→function levenshteinSimilarity(a: string, b: string): number {
665→  if (a === b) return 1;
666→  const longer = a.length > b.length ? a : b;
667→  const shorter = a.length > b.length ? b : a;
668→  if (longer.length === 0) return 1;
669→
670→  const costs: number[] = [];
671→  for (let i = 0; i <= longer.length; i++) {
672→    let lastValue = i;
673→    for (let j = 0; j <= shorter.length; j++) {
674→      if (i === 0) {
675→        costs[j] = j;
676→      } else if (j > 0) {
677→        let newValue = costs[j - 1];
678→        if (longer.charAt(i - 1) !== shorter.charAt(j - 1)) {
679→          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
680→        }
681→        costs[j - 1] = lastValue;
682→        lastValue = newValue;
683→      }
684→    }
685→    if (i > 0) costs[shorter.length] = lastValue;
686→  }
687→
688→  return (longer.length - costs[shorter.length]) / longer.length;
689→}
