185→    lines.push(`## Current Task: ${task.title} [${task.status}]`);
186→    if (task.description) lines.push(task.description);
187→
188→    const subtasks = taskScope.subtasks as Array<{ id: string; title: string; status: string }>;
189→    if (subtasks?.length) {
190→      lines.push("\nSubtasks:");
191→      for (const s of subtasks) lines.push(`  - [${s.status}] ${s.title}`);
192→    }
193→
194→    const siblings = taskScope.sibling_tasks as Array<{ id: string; title: string; status: string }>;
195→    if (siblings?.length) {
196→      lines.push("\nSibling tasks:");
197→      for (const s of siblings) lines.push(`  - [${s.status}] ${s.title}`);
198→    }
199→    lines.push("");
200→  }
201→
202→  // Decisions
203→  const decisions = p.decisions as { confirmed: unknown[]; provisional: unknown[]; contested: unknown[] } | undefined;
204→  if (decisions) {
205→    if (decisions.contested.length > 0) {
206→      lines.push("## CONTESTED DECISIONS (conflicts — do not proceed without human input)");
207→      for (const d of decisions.contested as Array<{ summary: string; rationale?: string }>) {
208→        lines.push(`  - ${d.summary}${d.rationale ? ` — ${d.rationale}` : ""}`);
