212→
213→    if (decisions.confirmed.length > 0) {
214→      lines.push("## Confirmed Decisions (follow these)");
215→      for (const d of decisions.confirmed as Array<{ summary: string }>) {
216→        lines.push(`  - ${d.summary}`);
217→      }
218→      lines.push("");
219→    }
220→
221→    if (decisions.provisional.length > 0) {
222→      lines.push("## Provisional Decisions (follow but flag for review)");
223→      for (const d of decisions.provisional as Array<{ summary: string }>) {
224→        lines.push(`  - ${d.summary}`);
225→      }
226→      lines.push("");
227→    }
228→  }
229→
230→  // Active tasks
231→  const tasks = p.active_tasks as Array<{ title: string; status: string; priority?: string }> | undefined;
232→  if (tasks?.length) {
233→    lines.push("## Active Tasks");
234→    for (const t of tasks) {
235→      lines.push(`  - [${t.status}]${t.priority ? ` (${t.priority})` : ""} ${t.title}`);
236→    }
237→    lines.push("");
238→  }
239→
240→  // Open questions
241→  const questions = p.open_questions as Array<{ text: string; status: string }> | undefined;
242→  if (questions?.length) {
243→    lines.push("## Open Questions");
244→    for (const q of questions) {
245→      lines.push(`  - [${q.status}] ${q.text}`);
246→    }
247→    lines.push("");
248→  }
249→
250→  // Recent changes
251→  const changes = p.recent_changes as Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }> | undefined;
252→  if (changes?.length) {
253→    lines.push("## Recent Changes");
