  async createSubtask(body: { parent_task_id: string; title: string; category?: string; rationale?: string }): Promise<unknown> {
    const res = await fetch(this.url("/tasks/subtask"), {
      method: "POST",
      headers: this.headers(),
      body: JSON.stringify(body),
