 65→/** List active decisions for a project, optionally filtered by area/category */
 66→export async function listProjectDecisions(input: {
 67→  surreal: Surreal;
 68→  workspaceRecord: RecordId<"workspace", string>;
 69→  projectRecord: RecordId<"project", string>;
 70→  area?: string;
 71→}): Promise<{
 72→  confirmed: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 73→  provisional: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 74→  contested: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 75→}> {
 76→  const areaFilter = input.area
 77→    ? `AND category = $area`
 78→    : "";
 79→
 80→  const [rows] = await input.surreal
 81→    .query<[DecisionRow[]]>(
 82→      `SELECT id, summary, status, rationale, decided_at, category, priority, created_at
 83→       FROM decision
 84→       WHERE workspace = $workspace
 85→         AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)
 86→         ${areaFilter}
 87→       ORDER BY created_at DESC LIMIT 50;`,
 88→      {
 89→        workspace: input.workspaceRecord,
 90→        project: input.projectRecord,
 91→        ...(input.area ? { area: input.area } : {}),
 92→      },
 93→    )
 94→    .collect<[DecisionRow[]]>();
 95→
 96→  type DecisionItem = { id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string };
 97→  const confirmed: DecisionItem[] = [];
 98→  const provisional: DecisionItem[] = [];
 99→  const contested: DecisionItem[] = [];
100→
101→  for (const d of rows) {
102→    const item: DecisionItem = {
103→      id: toId(d.id),
104→      summary: d.summary,
105→      status: d.status,
106→      ...(d.rationale ? { rationale: d.rationale } : {}),
107→      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
108→      ...(d.category ? { category: d.category } : {}),
109→    };
110→
111→    if (d.status === "contested") contested.push(item);
112→    else if (d.status === "provisional" || d.status === "inferred") provisional.push(item);
113→    else if (d.status === "confirmed") confirmed.push(item);
114→  }
115→
116→  return { confirmed, provisional, contested };
117→}
118→
119→/** Get task dependency tree (recursive) */
120→export async function getTaskDependencyTree(input: {
121→  surreal: Surreal;
122→  taskRecord: RecordId<"task", string>;
123→}): Promise<{
124→  task: { id: string; title: string; status: string };
125→  dependencies: Array<{ id: string; title: string; status: string; resolved: boolean }>;
126→  dependents: Array<{ id: string; title: string; status: string }>;
127→  subtasks: Array<{ id: string; title: string; status: string }>;
128→}> {
129→  const task = await input.surreal.select<TaskRow>(input.taskRecord);
130→  if (!task) throw new Error(`task not found: ${input.taskRecord.id}`);
131→
132→  const query = `
133→    -- Tasks this task depends on
134→    SELECT id, title, status
135→    FROM task
136→    WHERE id IN (SELECT VALUE out FROM depends_on WHERE \`in\` = $task);
137→
138→    -- Tasks that depend on this task
139→    SELECT id, title, status
140→    FROM task
141→    WHERE id IN (SELECT VALUE \`in\` FROM depends_on WHERE out = $task);
142→
143→    -- Subtasks
144→    SELECT id, title, status
145→    FROM task
146→    WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $task)
147→    ORDER BY created_at ASC;
148→  `;
149→
150→  const results = await input.surreal
151→    .query<[DependencyRow[], DependencyRow[], SubtaskRow[]]>(query, { task: input.taskRecord })
152→    .collect<[DependencyRow[], DependencyRow[], SubtaskRow[]]>();
153→
154→  const [deps, dependents, subtasks] = results;
155→
156→  return {
157→    task: { id: toId(task.id), title: task.title, status: task.status },
158→    dependencies: deps.map((d) => ({
159→      id: toId(d.id),
160→      title: d.title,
161→      status: d.status,
162→      resolved: d.status === "done" || d.status === "completed",
163→    })),
164→    dependents: dependents.map((d) => ({ id: toId(d.id), title: d.title, status: d.status })),
165→    subtasks: subtasks.map((s) => ({ id: toId(s.id), title: s.title, status: s.status })),
166→  };
167→}
168→
169→/** List architecture constraints for a project */
170→export async function listProjectConstraints(input: {
171→  surreal: Surreal;
172→  workspaceRecord: RecordId<"workspace", string>;
173→  projectRecord: RecordId<"project", string>;
174→  area?: string;
175→}): Promise<Array<{ text: string; source: string; severity: "hard" | "soft" }>> {
176→  // Constraints come from two sources:
177→  // 1. Decisions marked as confirmed/contested (hard constraints)
178→  // 2. Observations with severity "conflict" or "warning"
179→
180→  const areaFilter = input.area ? `AND category = $area` : "";
181→
182→  const query = `
183→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
184→
185→    SELECT summary AS text, "decision" AS source_type, status, id
186→    FROM decision
187→    WHERE workspace = $workspace
188→      AND id IN $project_entity_ids
189→      AND status IN ["confirmed", "contested"]
190→      ${areaFilter}
191→    ORDER BY created_at DESC LIMIT 30;
192→
193→    SELECT text, "observation" AS source_type, severity, id
194→    FROM observation
195→    WHERE workspace = $workspace
196→      AND status IN ["open", "acknowledged"]
197→      AND severity IN ["conflict", "warning"]
198→    ORDER BY created_at DESC LIMIT 20;
199→  `;
200→
201→  const results = await input.surreal
202→    .query<[null, Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>(
203→      query,
204→      {
205→        workspace: input.workspaceRecord,
206→        project: input.projectRecord,
207→        ...(input.area ? { area: input.area } : {}),
208→      },
209→    )
210→    .collect<[null, Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>();
211→
212→  const [, decisionRows, observationRows] = results;
213→
214→  const constraints: Array<{ text: string; source: string; severity: "hard" | "soft" }> = [];
215→
216→  for (const d of decisionRows) {
217→    constraints.push({
218→      text: d.text,
219→      source: `decision:${(d.id as RecordId<string, string>).id as string}`,
220→      severity: d.status === "contested" ? "hard" : "hard",
221→    });
222→  }
223→
224→  for (const o of observationRows) {
225→    constraints.push({
226→      text: o.text,
227→      source: `observation:${(o.id as RecordId<string, string>).id as string}`,
228→      severity: o.severity === "conflict" ? "hard" : "soft",
229→    });
230→  }
231→
232→  return constraints;
233→}
234→
235→/** List recent changes since a timestamp */
236→export async function listRecentChanges(input: {
237→  surreal: Surreal;
238→  workspaceRecord: RecordId<"workspace", string>;
239→  projectRecord?: RecordId<"project", string>;
240→  since: string;
241→}): Promise<Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }>> {
242→  const sinceDate = new Date(input.since);
243→
244→  const projectFilter = input.projectRecord
245→    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
246→    : "";
247→
248→  const query = `
249→    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
250→    FROM decision
251→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
252→    ORDER BY updated_at DESC LIMIT 20;
253→
254→    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
255→    FROM task
256→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
257→    ORDER BY updated_at DESC LIMIT 20;
258→
259→    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
260→    FROM question
261→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
262→    ORDER BY updated_at DESC LIMIT 20;
263→
264→    RETURN array::flatten([$recent_decisions, $recent_tasks, $recent_questions]);
265→  `;
266→
267→  const results = await input.surreal
268→    .query<[null, null, null, EntityChangeRow[]]>(query, {
269→      workspace: input.workspaceRecord,
270→      since: sinceDate,
271→      ...(input.projectRecord ? { project: input.projectRecord } : {}),
272→    })
273→    .collect<[null, null, null, EntityChangeRow[]]>();
274→
275→  return (results[3] ?? []).map((r) => ({
276→    entity_type: r.entity_type,
277→    entity_name: r.entity_name,
278→    change_type: r.change_type,
279→    changed_at: toIso(r.changed_at),
280→  }));
281→}
