586→/** Log a git commit to the graph */
587→export async function logCommit(input: {
588→  surreal: Surreal;
589→  workspaceRecord: RecordId<"workspace", string>;
590→  projectRecord: RecordId<"project", string>;
591→  sha: string;
592→  message: string;
593→  filesChanged: Array<{ path: string; change_type: string; lines_added: number; lines_removed: number }>;
594→  author: string;
595→  taskUpdates?: Array<{ task_id: string; new_status: string }>;
596→  decisionsDetected?: Array<{ name: string; rationale: string }>;
597→}): Promise<{ commit_id: string; tasks_updated: number; decisions_created: number }> {
598→  const now = new Date();
599→  const commitRecord = new RecordId("git_commit", randomUUID());
600→
601→  await input.surreal.create(commitRecord).content({
602→    sha: input.sha,
603→    message: input.message,
604→    workspace: input.workspaceRecord,
605→    authored_at: now,
606→    created_at: now,
607→  });
608→
609→  // Update task statuses
610→  let tasksUpdated = 0;
611→  if (input.taskUpdates?.length) {
612→    for (const update of input.taskUpdates) {
613→      const taskRecord = new RecordId("task", update.task_id);
614→      await input.surreal.update(taskRecord).merge({
615→        status: update.new_status,
616→        updated_at: now,
617→      });
618→      tasksUpdated++;
619→    }
620→  }
621→
622→  // Create provisional decisions if flagged
623→  let decisionsCreated = 0;
624→  if (input.decisionsDetected?.length) {
625→    for (const decision of input.decisionsDetected) {
626→      const decisionRecord = new RecordId("decision", randomUUID());
627→      await input.surreal.create(decisionRecord).content({
628→        summary: decision.name,
629→        rationale: decision.rationale,
630→        status: "provisional",
631→        decided_by_name: "code-agent",
632→        workspace: input.workspaceRecord,
633→        source_commit: commitRecord,
634→        created_at: now,
635→        updated_at: now,
636→      });
637→
638→      // Link decision to project
639→      await input.surreal
640→        .relate(decisionRecord, new RecordId("belongs_to", randomUUID()), input.projectRecord, {
641→          added_at: now,
642→        })
643→        .output("after");
644→
645→      // Create implemented_by edge
646→      await input.surreal
647→        .relate(decisionRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
648→          commit_sha: input.sha,
649→          linked_at: now,
650→        })
651→        .output("after");
652→
653→      decisionsCreated++;
654→    }
655→  }
656→
657→  return {
658→    commit_id: toId(commitRecord),
659→    tasks_updated: tasksUpdated,
660→    decisions_created: decisionsCreated,
661→  };
662→}
663→
664→// ---------------------------------------------------------------------------
665→// Utility
666→// ---------------------------------------------------------------------------
667→
668→function levenshteinSimilarity(a: string, b: string): number {
669→  if (a === b) return 1;
670→  const longer = a.length > b.length ? a : b;
671→  const shorter = a.length > b.length ? b : a;
672→  if (longer.length === 0) return 1;
673→
674→  const costs: number[] = [];
675→  for (let i = 0; i <= longer.length; i++) {
676→    let lastValue = i;
677→    for (let j = 0; j <= shorter.length; j++) {
678→      if (i === 0) {
679→        costs[j] = j;
680→      } else if (j > 0) {
681→        let newValue = costs[j - 1];
682→        if (longer.charAt(i - 1) !== shorter.charAt(j - 1)) {
683→          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
684→        }
685→        costs[j - 1] = lastValue;
686→        lastValue = newValue;
687→      }
688→    }
689→    if (i > 0) costs[shorter.length] = lastValue;
690→  }
691→
692→  return (longer.length - costs[shorter.length]) / longer.length;
693→}
