 52→async function parseJsonBody<T>(request: Request): Promise<T | Response> {
 53→  try {
 54→    return (await request.json()) as T;
 55→  } catch {
 56→    return jsonError("invalid JSON body", 400);
 57→  }
 58→}
 59→
 60→const ENTITY_TABLES: GraphEntityTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question", "observation"];
 61→
 62→function normalizeTokens(value: string): Set<string> {
 63→  return new Set(
 64→    value
 65→      .toLowerCase()
 66→      .replace(/[^a-z0-9\s]/g, " ")
 67→      .split(/\s+/)
 68→      .map((t) => t.trim())
 69→      .filter((t) => t.length > 2),
 70→  );
 71→}
 72→
 73→function hasTokenOverlap(a: Set<string>, b: Set<string>): boolean {
 74→  for (const v of a) {
 75→    if (b.has(v)) return true;
 76→  }
 77→  return false;
 78→}
