278→  // Tier 2 — Reason
279→  // =========================================================================
280→
281→  /** POST /api/mcp/:workspaceId/decisions/resolve — Infer decision from graph */
282→  async function handleResolveDecision(workspaceId: string, request: Request): Promise<Response> {
283→    const auth = await requireAuth(request, workspaceId);
284→    if (auth instanceof Response) return auth;
285→
286→    const body = await parseJsonBody<{
287→      question: string;
288→      options?: string[];
289→      context?: { project?: string; feature?: string };
290→    }>(request);
291→    if (body instanceof Response) return body;
292→    if (!body.question) return jsonError("question is required", 400);
293→
294→    // Embed the question and search for related decisions
295→    const queryEmbedding = await createEmbeddingVector(
296→      deps.embeddingModel,
297→      body.question,
298→      config.embeddingDimension,
299→    );
300→
301→    if (!queryEmbedding) {
302→      return jsonResponse({
303→        decision: undefined,
304→        confidence: 0,
305→        status: "unresolved",
306→        rationale: "Could not create embedding for question",
307→        sources: [],
308→      }, 200);
309→    }
310→
311→    const projectRecord = body.context?.project
312→      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.context.project })
313→      : undefined;
314→
315→    const candidates = await searchEntitiesByEmbedding({
316→      surreal,
317→      workspaceRecord: auth.workspaceRecord,
318→      queryEmbedding,
319→      kinds: ["decision"],
320→      ...(projectRecord ? { projectRecord } : {}),
321→      limit: 10,
322→    });
323→
324→    // Check if any existing decision resolves the question
325→    const questionTokens = normalizeTokens(body.question);
326→    const relevant = candidates.filter((c) => {
327→      const tokens = normalizeTokens(c.name);
328→      return c.score >= 0.78 && hasTokenOverlap(questionTokens, tokens);
329→    });
330→
331→    if (relevant.length > 0) {
332→      const best = relevant[0];
333→      return jsonResponse({
334→        decision: best.name,
335→        confidence: Number(best.score.toFixed(4)),
336→        status: best.status ?? "unknown",
337→        rationale: `Existing ${best.status} decision found with ${(best.score * 100).toFixed(1)}% similarity`,
338→        sources: relevant.map((r) => ({ id: `${r.kind}:${r.id}`, name: r.name, score: Number(r.score.toFixed(4)) })),
339→      }, 200);
340→    }
341→
342→    return jsonResponse({
343→      decision: undefined,
344→      confidence: 0,
345→      status: "unresolved",
346→      rationale: "No existing decision found that resolves this question",
347→      sources: candidates.slice(0, 5).map((c) => ({
348→        id: `${c.kind}:${c.id}`,
349→        name: c.name,
350→        score: Number(c.score.toFixed(4)),
351→      })),
352→    }, 200);
353→  }
354→
355→  /** POST /api/mcp/:workspaceId/constraints/check — Check proposed action */
356→  async function handleCheckConstraints(workspaceId: string, request: Request): Promise<Response> {
357→    const auth = await requireAuth(request, workspaceId);
358→    if (auth instanceof Response) return auth;
359→
360→    const body = await parseJsonBody<{ proposed_action: string; project?: string }>(request);
361→    if (body instanceof Response) return body;
362→    if (!body.proposed_action) return jsonError("proposed_action is required", 400);
363→
364→    const queryEmbedding = await createEmbeddingVector(
365→      deps.embeddingModel,
366→      body.proposed_action,
367→      config.embeddingDimension,
368→    );
369→
370→    if (!queryEmbedding) {
371→      return jsonResponse({ hard_conflicts: [], soft_tensions: [], supporting: [], proceed: true }, 200);
372→    }
373→
374→    const projectRecord = body.project
375→      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.project })
376→      : undefined;
377→
378→    const candidates = await listDecisionConstraintCandidates({
379→      surreal,
380→      workspaceRecord: auth.workspaceRecord,
381→      queryEmbedding,
382→      ...(projectRecord ? { projectRecord } : {}),
383→      limit: 14,
384→    });
385→
386→    const actionTokens = normalizeTokens(body.proposed_action);
387→    const hardConflicts: Array<{ id: string; name: string; score: number; reason: string }> = [];
388→    const softTensions: Array<{ id: string; name: string; score: number; reason: string }> = [];
389→    const supporting: Array<{ id: string; name: string; score: number; reason: string }> = [];
390→
391→    for (const candidate of candidates) {
392→      const candidateTokens = normalizeTokens(candidate.name);
393→      const overlap = hasTokenOverlap(actionTokens, candidateTokens);
394→      const status = candidate.status?.toLowerCase();
395→
396→      if (candidate.kind === "decision" && overlap && (status === "contested" || status === "superseded")) {
397→        hardConflicts.push({
398→          id: `${candidate.kind}:${candidate.id}`,
399→          name: candidate.name,
400→          score: Number(candidate.score.toFixed(4)),
401→          reason: `Decision is marked ${status}.`,
402→        });
403→        continue;
404→      }
405→
406→      if (candidate.kind === "decision" && candidate.score >= 0.86 && overlap) {
407→        supporting.push({
408→          id: `${candidate.kind}:${candidate.id}`,
409→          name: candidate.name,
410→          score: Number(candidate.score.toFixed(4)),
411→          reason: "High-similarity decision aligns with proposed action.",
412→        });
413→        continue;
414→      }
415→
416→      if (candidate.score >= 0.72) {
417→        softTensions.push({
418→          id: `${candidate.kind}:${candidate.id}`,
419→          name: candidate.name,
420→          score: Number(candidate.score.toFixed(4)),
421→          reason: overlap
422→            ? "Related decision/question may require consistency checks."
423→            : "Semantically related context may be affected.",
424→        });
425→      }
426→    }
427→
