626→  /** POST /api/mcp/:workspaceId/observations — Log a codebase observation */
627→  async function handleLogObservation(workspaceId: string, request: Request): Promise<Response> {
628→    const auth = await requireAuth(request, workspaceId);
629→    if (auth instanceof Response) return auth;
630→
631→    const body = await parseJsonBody<{
632→      text: string;
633→      category: string;
634→      severity: string;
635→      target?: string;
636→      session_id?: string;
637→    }>(request);
638→    if (body instanceof Response) return body;
639→    if (!body.text) return jsonError("text is required", 400);
640→    if (!body.category) return jsonError("category is required", 400);
641→    if (!body.severity) return jsonError("severity is required", 400);
642→
643→    if (!OBSERVATION_TYPES.includes(body.category as ObservationType)) {
644→      return jsonError(`invalid category: must be one of ${OBSERVATION_TYPES.join(", ")}`, 400);
645→    }
646→
647→    const validSeverities = ["info", "warning", "conflict"];
648→    if (!validSeverities.includes(body.severity)) {
649→      return jsonError("invalid severity: must be info, warning, or conflict", 400);
650→    }
651→
652→    type ObserveTable = "project" | "feature" | "task" | "decision" | "question";
653→    let relatedRecord: RecordId<ObserveTable, string> | undefined;
654→    if (body.target) {
655→      try {
656→        relatedRecord = parseRecordIdString(body.target, ["project", "feature", "task", "decision", "question"] as const);
657→      } catch {
658→        return jsonError(`invalid target entity: ${body.target}`, 400);
659→      }
660→    }
661→
662→    const embedding = await createEmbeddingVector(
663→      deps.embeddingModel,
664→      body.text,
665→      config.embeddingDimension,
666→    );
667→
668→    const sourceSessionRecord = body.session_id
669→      ? new RecordId("agent_session", body.session_id)
670→      : undefined;
671→
672→    const now = new Date();
673→
674→    const observationRecord = await createObservation({
675→      surreal,
676→      workspaceRecord: auth.workspaceRecord,
677→      text: body.text,
678→      severity: body.severity as ObservationSeverity,
679→      observationType: body.category as ObservationType,
680→      sourceAgent: "code-agent",
681→      now,
682→      ...(sourceSessionRecord ? { sourceSessionRecord } : {}),
683→      ...(relatedRecord ? { relatedRecord } : {}),
684→      ...(embedding ? { embedding } : {}),
685→    });
686→
687→    // Create observed_in edge: observation -> agent_session
688→    if (sourceSessionRecord) {
689→      await surreal
690→        .relate(observationRecord, new RecordId("observed_in", crypto.randomUUID()), sourceSessionRecord, {
691→          added_at: now,
692→        })
693→        .output("after");
694→    }
695→
696→    logInfo("mcp.observation.created", "Observation logged via MCP", {
697→      workspaceId,
698→      observationId: observationRecord.id as string,
699→      observationType: body.category,
700→      severity: body.severity,
701→    });
702→
703→    return jsonResponse({
704→      observation_id: `observation:${observationRecord.id as string}`,
705→      severity: body.severity,
706→      status: "open",
707→    }, 201);
708→  }
