830→  /** POST /api/mcp/:workspaceId/commits/check — Pre-commit LLM analysis */
831→  async function handleCheckCommit(workspaceId: string, request: Request): Promise<Response> {
832→    const auth = await requireAuth(request, workspaceId);
833→    if (auth instanceof Response) return auth;
834→
835→    const body = await parseJsonBody<{
836→      project_id: string;
837→      diff: string;
838→      commit_message: string;
839→    }>(request);
840→    if (body instanceof Response) return body;
841→    if (!body.project_id) return jsonError("project_id is required", 400);
842→    if (!body.diff) return jsonError("diff is required", 400);
843→
844→    const projectRecord = new RecordId("project", body.project_id);
845→
846→    // Load project context for analysis
847→    const [decisions, constraints, activeTasks] = await Promise.all([
848→      listProjectDecisions({
849→        surreal,
850→        workspaceRecord: auth.workspaceRecord,
851→        projectRecord,
852→      }),
853→      listProjectConstraints({
854→        surreal,
855→        workspaceRecord: auth.workspaceRecord,
856→        projectRecord,
857→      }),
858→      surreal.query<[Array<{ title: string; status: string }>]>(
859→        `SELECT title, status FROM task WHERE workspace = $ws AND status IN ["todo", "in_progress"] ORDER BY created_at DESC LIMIT 30;`,
860→        { ws: auth.workspaceRecord },
861→      ).then((r) => r[0] ?? []),
862→    ]);
863→
864→    // Truncate diff for token budget
865→    const truncatedDiff = body.diff.length > 8000 ? body.diff.slice(0, 8000) + "\n... (truncated)" : body.diff;
866→
867→    const result = await generateObject({
868→      model: extractionModel,
869→      schema: commitCheckSchema,
870→      temperature: 0.1,
871→      system: [
872→        "You are a pre-commit analyzer for a knowledge graph-integrated development workflow.",
873→        "Analyze the staged git diff and commit message against the project context.",
874→        "Detect:",
875→        "1. Task completions — does this commit complete or substantially finish any active tasks?",
876→        "2. Unlogged decisions — does this commit introduce architectural or design decisions not already in the knowledge graph?",
877→        "3. Constraint violations — does this commit contradict any confirmed decisions or active constraints?",
878→        "Be conservative: only flag items with genuine evidence in the diff. Empty arrays are fine if nothing is detected.",
879→      ].join("\n"),
880→      prompt: [
881→        "## Commit message",
882→        body.commit_message || "(no message)",
883→        "",
884→        "## Staged diff",
885→        truncatedDiff,
886→        "",
887→        "## Active tasks",
888→        activeTasks.length > 0
889→          ? activeTasks.map((t) => `- [${t.status}] ${t.title}`).join("\n")
890→          : "(no active tasks)",
891→        "",
892→        "## Recent decisions",
893→        (() => {
894→          const allDecisions = [...decisions.confirmed, ...decisions.provisional, ...decisions.contested];
895→          return allDecisions.length > 0
896→            ? allDecisions.map((d) => `- [${d.status}] ${d.summary}`).join("\n")
897→            : "(no decisions)";
898→        })(),
899→        "",
900→        "## Active constraints",
901→        constraints.length > 0
902→          ? constraints.map((c) => `- [${c.severity}] ${c.text}`).join("\n")
903→          : "(no constraints)",
904→      ].join("\n"),
905→    });
906→
907→    return jsonResponse(result.object, 200);
908→  }
