 77→export async function resolveObservation(input: {
 78→  surreal: Surreal;
 79→  workspaceRecord: RecordId<"workspace", string>;
 80→  observationRecord: ObservationRecord;
 81→  now: Date;
 82→  resolvedByRecord?: RecordId<"person", string>;
 83→}): Promise<void> {
 84→  const row = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(input.observationRecord);
 85→  if (!row) {
 86→    throw new Error(`observation not found: ${input.observationRecord.id as string}`);
 87→  }
 88→
 89→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
 90→    throw new Error("observation is outside the current workspace scope");
 91→  }
 92→
 93→  await input.surreal.update(input.observationRecord).merge({
 94→    status: "resolved" satisfies ObservationStatus,
 95→    resolved_at: input.now,
 96→    ...(input.resolvedByRecord ? { resolved_by: input.resolvedByRecord } : {}),
 97→    updated_at: input.now,
 98→  });
