103→    "Check if an existing decision in the graph answers your question. Use before making a new decision — the graph may already have the answer from a previous agent or human.",
104→    {
105→      question: z.string().describe("The question you need answered (e.g. 'Should this endpoint use REST or tRPC?')"),
106→      options: z.array(z.string()).optional().describe("Options you've identified"),
107→      context: z
108→        .object({
109→          project: z.string().optional(),
110→          feature: z.string().optional(),
111→        })
112→        .optional()
113→        .describe("Project/feature scope to search within"),
114→    },
115→    async (input) => {
116→      const result = await client.resolveDecision(input);
117→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
118→    },
119→  );
120→
121→  server.tool(
122→    "check_constraints",
123→    "Check if a proposed action conflicts with existing decisions or constraints. Returns hard conflicts, soft tensions, and supporting context.",
124→    {
125→      proposed_action: z.string().describe("What you're proposing to do (e.g. 'Add Redis dependency for caching')"),
126→      project: z.string().optional().describe("Project scope"),
127→    },
128→    async (input) => {
129→      const result = await client.checkConstraints(input);
130→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
131→    },
132→  );
133→
134→  // =========================================================================
135→  // Tier 3 — Write Tools
136→  // =========================================================================
137→
138→  server.tool(
139→    "create_provisional_decision",
140→    "Create a provisional decision when you make an implementation choice the graph doesn't cover. This surfaces for human review in the feed. Use after resolve_decision returns unresolved.",
141→    {
142→      name: z.string().describe("Concise decision name (e.g. 'Use token bucket for rate limiting')"),
143→      rationale: z.string().describe("Why this decision was made"),
144→      context: z
145→        .object({
146→          project: z.string().optional(),
147→          feature: z.string().optional(),
148→        })
149→        .optional()
150→        .describe("Project/feature this decision belongs to"),
151→      options_considered: z.array(z.string()).optional().describe("Other options that were considered"),
152→    },
153→    async (input) => {
154→      const result = await client.createProvisionalDecision(input);
155→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
156→    },
157→  );
158→
159→  server.tool(
160→    "ask_question",
161→    "Ask a question when genuinely uncertain. Creates a question entity for human review in the feed. Better than guessing or creating a provisional decision when you don't know the answer.",
162→    {
163→      text: z.string().describe("The question"),
164→      context: z
165→        .object({
166→          project: z.string().optional(),
167→          feature: z.string().optional(),
168→          task: z.string().optional(),
169→        })
170→        .optional()
171→        .describe("Scope for the question"),
172→      options: z.array(z.string()).optional().describe("Options you've identified (helps human answer faster)"),
173→      blocking_task: z.string().optional().describe("Task ID this question blocks (creates BLOCKS edge)"),
174→    },
175→    async (input) => {
176→      const result = await client.askQuestion(input);
177→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
178→    },
179→  );
180→
181→  server.tool(
182→    "update_task_status",
183→    "Update a task's status. Triggers automatic subtask rollup on parent tasks.",
184→    {
185→      task_id: z.string().describe("Task ID"),
186→      status: z.string().describe("New status: todo, in_progress, blocked, completed, done"),
187→      notes: z.string().optional().describe("Optional notes about the status change"),
188→    },
189→    async (input) => {
190→      const result = await client.updateTaskStatus(input);
191→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
192→    },
193→  );
194→
195→  server.tool(
196→    "create_subtask",
197→    "Create a subtask under a parent task. Use to break work into smaller pieces. Includes semantic dedup — returns existing subtask if a similar one already exists.",
198→    {
199→      parent_task_id: z.string().describe("Parent task ID to add subtask under"),
200→      title: z.string().describe("Subtask title"),

200→      title: z.string().describe("Subtask title"),
201→      category: z.string().optional().describe("Category (inherits from parent if not specified)"),
202→      rationale: z.string().optional().describe("Why this subtask is needed"),
203→    },
204→    async (input) => {
205→      const result = await client.createSubtask(input);
206→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
207→    },
208→  );
209→
210→  server.tool(
211→    "log_implementation_note",
212→    "Append an implementation note to any entity (decision, task, feature). Use to record what was implemented and how.",
213→    {
214→      entity_id: z.string().describe("Entity ID in table:id format (e.g. decision:abc123)"),
215→      note: z.string().describe("What was implemented and how"),
216→      files_changed: z.array(z.string()).optional().describe("Paths of files touched"),
217→    },
218→    async (input) => {
219→      const result = await client.logImplementationNote(input);
220→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
221→    },
222→  );
223→
224→  server.tool(
225→    "log_observation",
226→    "Log a codebase observation to the knowledge graph. Use when you notice contradictions between code and decisions, duplicated logic, missing implementations, deprecated patterns, recurring patterns, or anomalies. Creates an observation entity visible in the feed and to other agents.",
227→    {
228→      text: z.string().describe("What you observed — include file paths and specifics so a human can act on it"),
229→      category: z
230→        .enum(["contradiction", "duplication", "missing", "deprecated", "pattern", "anomaly"])
231→        .describe(
232→          "contradiction: code contradicts a decision or spec. duplication: same logic in multiple places. missing: expected thing is absent (tests, error handling, docs). deprecated: outdated dependency or pattern. pattern: recurring pattern worth noting. anomaly: something unexpected.",
233→        ),
234→      severity: z
235→        .enum(["info", "warning", "conflict"])
236→        .describe(
237→          "info: awareness-level, no action needed. warning: risk that should be addressed. conflict: contradiction needing human resolution.",
238→        ),
239→      target: z.string().optional().describe("Entity this observation is about, in table:id format (e.g. decision:abc123, task:def456)"),
240→      session_id: z.string().optional().describe("Current agent session ID to link this observation to"),
241→    },
242→    async (input) => {
243→      const result = await client.logObservation(input);
244→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
245→    },
246→  );
247→
248→  // =========================================================================
249→  // Connect via stdio
250→  // =========================================================================
251→
252→  const transport = new StdioServerTransport();
253→  await server.connect(transport);
254→}
