  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type {
  3→  ContextPacket,
  4→  DecisionContext,
  5→  TaskContext,
  6→  QuestionContext,
  7→  ObservationContext,
  8→  TaskScopeContext,
  9→  RecentChangeContext,
 10→} from "./types";
 11→
 12→type ProjectRow = {
 13→  id: RecordId<"project", string>;
 14→  name: string;
 15→  status: string;
 16→  description?: string;
 17→};
 18→
 19→type DecisionRow = {
 20→  id: RecordId<"decision", string>;
 21→  summary: string;
 22→  status: string;
 23→  rationale?: string;
 24→  decided_at?: Date | string;
 25→  category?: string;
 26→  priority?: string;
 27→};
 28→
 29→type TaskRow = {
 30→  id: RecordId<"task", string>;
 31→  title: string;
 32→  status: string;
 33→  priority?: string;
 34→  category?: string;
 35→  description?: string;
 36→  source_session?: RecordId<"agent_session", string>;
 37→};
 38→
 39→type QuestionRow = {
 40→  id: RecordId<"question", string>;
 41→  text: string;
 42→  status: string;
 43→  context?: string;
 44→  priority?: string;
 45→};
 46→
 47→type ObservationRow = {
 48→  id: RecordId<"observation", string>;
 49→  text: string;
 50→  severity: string;
 51→  status: string;
 52→  category?: string;
 53→  observation_type?: string;
 54→};
 55→
 56→type AgentSessionRow = {
 57→  id: RecordId<"agent_session", string>;
 58→  agent: string;
 59→  ended_at?: Date | string;
 60→  summary?: string;
 61→};
 62→
 63→type SubtaskRow = {
 64→  id: RecordId<"task", string>;
 65→  title: string;
 66→  status: string;
 67→};
 68→
 69→type FeatureRow = {
 70→  id: RecordId<"feature", string>;
 71→  name: string;
 72→  description?: string;
 73→};
 74→
 75→type DependencyRow = {
 76→  id: RecordId<"task", string>;
 77→  title: string;
 78→  status: string;
 79→};
 80→
 81→function toId(record: RecordId<string, string>): string {
 82→  return `${record.table.name}:${record.id as string}`;
 83→}
 84→
 85→function toIso(value: Date | string | undefined): string {
 86→  if (!value) return "";
 87→  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
 88→}
 89→
 90→/** Build a broad project context packet (all decisions, tasks, questions for a project) */
 91→export async function buildProjectContext(input: {
 92→  surreal: Surreal;
 93→  workspaceRecord: RecordId<"workspace", string>;
 94→  workspaceName: string;
 95→  projectRecord: RecordId<"project", string>;
 96→  taskId?: string;
 97→  since?: string;
 98→}): Promise<ContextPacket> {
 99→  const { surreal, workspaceRecord, workspaceName, projectRecord, taskId } = input;
100→
101→  // Load project details
102→  const project = await surreal.select<ProjectRow>(projectRecord);
103→  if (!project) {
104→    throw new Error(`project not found: ${projectRecord.id}`);
105→  }
106→
107→  // Load project-scoped entities in parallel
108→  const projectEntitiesQuery = `
109→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
110→
111→    SELECT id, summary, status, rationale, decided_at, category, priority
112→    FROM decision
113→    WHERE workspace = $workspace AND id IN $project_entity_ids
114→    ORDER BY created_at DESC LIMIT 50;
115→
116→    SELECT id, title, status, priority, category, description, source_session
117→    FROM task
118→    WHERE workspace = $workspace AND id IN $project_entity_ids
119→    ORDER BY created_at DESC LIMIT 50;
120→
121→    SELECT id, text, status, context, priority
122→    FROM question
123→    WHERE workspace = $workspace AND id IN $project_entity_ids
124→    ORDER BY created_at DESC LIMIT 30;
125→
126→    SELECT id, text, severity, status, category, observation_type
127→    FROM observation
128→    WHERE workspace = $workspace AND status IN ["open", "acknowledged"]
129→    ORDER BY created_at DESC LIMIT 20;
130→  `;
131→
132→  const results = await surreal
133→    .query<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[]]>(projectEntitiesQuery, {
134→      project: projectRecord,
135→      workspace: workspaceRecord,
136→    })
137→    .collect<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[]]>();
138→
139→  const [, decisionRows, taskRows, questionRows, observationRows] = results;
140→
141→  // Categorize decisions by status
142→  const confirmed: DecisionContext[] = [];
143→  const provisional: DecisionContext[] = [];
144→  const contested: DecisionContext[] = [];
145→
146→  for (const d of decisionRows) {
147→    const ctx: DecisionContext = {
148→      id: toId(d.id),
149→      summary: d.summary,
150→      status: d.status,
151→      ...(d.rationale ? { rationale: d.rationale } : {}),
152→      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
153→      ...(d.category ? { category: d.category } : {}),
154→      ...(d.priority ? { priority: d.priority } : {}),
155→    };
156→
157→    if (d.status === "contested") {
158→      contested.push(ctx);
159→    } else if (d.status === "provisional" || d.status === "inferred") {
160→      provisional.push(ctx);
161→    } else if (d.status === "confirmed") {
162→      confirmed.push(ctx);
163→    }
164→  }
165→
166→  // Map tasks
167→  const activeTasks: TaskContext[] = taskRows
168→    .filter((t) => t.status !== "done" && t.status !== "completed")
169→    .map((t) => ({
170→      id: toId(t.id),
171→      title: t.title,
172→      status: t.status,
173→      ...(t.priority ? { priority: t.priority } : {}),
174→      ...(t.category ? { category: t.category } : {}),
175→      ...(t.source_session ? { source_session: toId(t.source_session) } : {}),
176→    }));
177→
178→  // Map questions
179→  const openQuestions: QuestionContext[] = questionRows
180→    .filter((q) => q.status !== "answered" && q.status !== "resolved")
181→    .map((q) => ({
182→      id: toId(q.id),
183→      text: q.text,
184→      status: q.status,
185→      ...(q.context ? { context: q.context } : {}),
186→      ...(q.priority ? { priority: q.priority } : {}),
187→    }));
188→
189→  // Map observations
190→  const observations: ObservationContext[] = observationRows.map((o) => ({
191→    id: toId(o.id),
192→    text: o.text,
193→    severity: o.severity,
194→    status: o.status,
195→    ...(o.category ? { category: o.category } : {}),
196→    ...(o.observation_type ? { observation_type: o.observation_type } : {}),
197→  }));
198→
199→  // Build recent changes if `since` provided
200→  const recentChanges: RecentChangeContext[] = input.since
201→    ? await loadRecentChanges(surreal, workspaceRecord, projectRecord, input.since)
202→    : [];
203→
204→  // Build task scope if taskId provided
205→  let taskScope: TaskScopeContext | undefined;
206→  if (taskId) {
207→    taskScope = await buildTaskScope(surreal, workspaceRecord, projectRecord, taskId);
208→  }
209→
210→  return {
211→    workspace: { id: workspaceRecord.id as string, name: workspaceName },
212→    project: {
213→      id: projectRecord.id as string,
214→      name: project.name,
215→      status: project.status,
216→      ...(project.description ? { description: project.description } : {}),
217→    },
218→    ...(taskScope ? { task_scope: taskScope } : {}),
219→    decisions: { confirmed, provisional, contested },
220→    active_tasks: activeTasks,
221→    open_questions: openQuestions,
222→    recent_changes: recentChanges,
223→    observations,
224→  };
225→}
226→
227→/** Build task-scoped context: subtasks, parent feature, siblings, dependencies, related sessions */
228→async function buildTaskScope(
229→  surreal: Surreal,
230→  _workspaceRecord: RecordId<"workspace", string>,
231→  _projectRecord: RecordId<"project", string>,
232→  taskId: string,
233→): Promise<TaskScopeContext> {
234→  const taskRecord = new RecordId("task", taskId);
235→  const task = await surreal.select<TaskRow>(taskRecord);
236→  if (!task) {
237→    throw new Error(`task not found: ${taskId}`);
238→  }
239→
240→  // Load subtasks, parent feature, dependencies, and related sessions in parallel
241→  const taskScopeQuery = `
242→    -- Subtasks of this task
243→    SELECT id, title, status
244→    FROM task
245→    WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $task)
246→    ORDER BY created_at ASC;
247→
248→    -- Parent feature (via has_task edge)
249→    SELECT id, name, description
250→    FROM feature
251→    WHERE id IN (SELECT VALUE \`in\` FROM has_task WHERE out = $task)
252→    LIMIT 1;
253→
254→    -- Dependencies (tasks this task depends on)
255→    SELECT id, title, status
256→    FROM task
257→    WHERE id IN (SELECT VALUE out FROM depends_on WHERE \`in\` = $task);
258→
259→    -- Recent agent sessions that touched this task
260→    SELECT id, agent, ended_at, summary
261→    FROM agent_session
262→    WHERE task_id = $task AND ended_at != NONE
263→    ORDER BY ended_at DESC LIMIT 5;
264→  `;
265→
266→  const results = await surreal
267→    .query<[SubtaskRow[], FeatureRow[], DependencyRow[], AgentSessionRow[]]>(taskScopeQuery, {
268→      task: taskRecord,
269→    })
270→    .collect<[SubtaskRow[], FeatureRow[], DependencyRow[], AgentSessionRow[]]>();
